import sys,json,re
raw=sys.stdin.read()
m=re.search(r"\{.*\}",raw,re.S)
d=json.loads(m.group(0))
def walk(o):
  if isinstance(o,dict):
    if "label" in o:
      lbl=o.get("label"); uses=o.get("uses") or o.get("proof_uses") or []
      keys={k:o[k] for k in o if k in ("proved","stmt_proved","proof_proved","leanok","can_prove","status","color")}
      print(lbl,"=>",json.dumps(o.get("uses","NA")), "| stmtkeys", keys)
    for v in o.values(): walk(v)
  elif isinstance(o,list):
    for v in o: walk(v)
walk(d)
' 2>&1 | grep -iE "rigidity|dense|saturat|cube|morphism_P1|genusZero|genus0"

